      if (!document.getElementById('modal')) {
        const el = document.createElement('div');
        el.id = 'modal';
        document.body.appendChild(el);
      }
      return <Story />;
    },
    (Story) => (
      <MemoryRouter>
        <StoreProvider store={store}>
          <ThemeProvider theme={lightTheme}>
