  args: { children: 'Order now' },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /order now/i });
    await expect(button).toBeVisible();
    await expect(getComputedStyle(button).borderRadius).toBe('4px');
  },
};

